module watchdog_timer(
    input clk,
    input rst,
    input enable,
    output reg timeout
);
    reg [3:0] obf_counter; // 4-bit obf_counter for counting up to 10

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_counter <= 0;
            timeout <= 0;
        end else if (enable) begin
            if (obf_counter < 10) begin
                obf_counter <= obf_counter + 1;
                timeout <= 0;
            end else begin
                timeout <= 1;
            end
        end
    end
endmodule
